// Handle login
app.post('/login', (req, res, next) => {
  const { username, password, client_id, redirect_uri, state } = req.body;
  
  const user = users.get(username);
  if (!user || user.password !== password) {
    return res.status(401).send('Invalid credentials');
  }
  
  // Store user session or set session cookie
  req.session.userId = user.id;
  
  // Redirect to authorization endpoint with proper parameters
  const authUrl = new URL('/oauth/authorize', 'http://localhost:3000');
  authUrl.searchParams.append('client_id', client_id);
  authUrl.searchParams.append('redirect_uri', redirect_uri);
  authUrl.searchParams.append('response_type', 'code');
  authUrl.searchParams.append('state', state);
  
  res.redirect(authUrl.toString());
});

// Authorization endpoint
app.get('/oauth/authorize', async (req, res, next) => {
  const request = new Request({
    method: 'GET',
    query: req.query,
    headers: req.headers
  });
  
  const response = new Response({
    headers: {}
  });
  
  try {
    const auth = await oauth2Server.authorize(request, response);
    res.redirect(response.headers.Location);
  } catch (error) {
    res.status(error.statusCode || 500).json({ error: error.message });
  }
});

// Token endpoint
app.post('/oauth/token', async (req, res, next) => {
  const request = new Request({
    method: 'POST',
    query: req.query,
    body: req.body,
    headers: req.headers
  });
  
  const response = new Response({
    headers: {}
  });
  
  try {
    const token = await oauth2Server.token(request, response);
    res.json(token);
  } catch (error) {
    res.status(error.statusCode || 500).json({ error: error.message });
  }
});

// Middleware to check if user is authenticated
app.use((req, res, next) => {
  if (req.path === '/login' || req.path === '/oauth/authorize' || req.path === '/oauth/token') {
    return next();
  }
  
  if (req.session.userId) {
    next();
  } else {
    res.redirect('/login?client_id=' + (req.query.client_id || '') + '&redirect_uri=' + (req.query.redirect_uri || '') + '&state=' + (req.query.state || ''));
  }
});

